import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge, getUrlParamNew } from '@/utils';

interface Extra {
  msg_id: number;
  has_likes: boolean;
  tal_name: string;
}

type IncentiveDetailType = ResponseType<{
  id: string;
  content: string;
  title: string;
  extra: Extra;
}>;


export const getIncentiveDetail = async (params: {
  interact_id: string;
  tal_id: string
}): IncentiveDetailType => {
  const token = await getTokenByBridge();
  const familyId = getUrlParamNew('family_id') || ''
  return ApiService.post('/parent/api/v1/incentive/detail', {
    ...params,
    token
  }, {
    headers: {
      'X-Tal-FamilyId': familyId
    }
  });
};

export const incentiveInteract = async (params: {
  type: number;
  interact_id: string;
}): ResponseType => {
  const token = await getTokenByBridge();
  const familyId = getUrlParamNew('family_id') || ''
  return ApiService.post('/parent/api/v1/incentive/interact', {
    ...params,
    token
  }, {
    headers: {
      'X-Tal-FamilyId': familyId
    }
  });
};

// 将消息改为已读状态
export const changeMsgReadStatus = async (id: number) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/notice/set-read', {
    id,
    type: 1,
    token
  });
};
